function digitSum(n) {
    return n.toString().split('').reduce((sum, digit) => sum + parseInt(digit), 0);
}

function minimumBeautiful(n, target) {
    let x = 0;
    while (digitSum(n + x) > target) {
        ++x;
    }
    return x;
}
```

