public int digitSum(int n) {
    int sum = 0;
    while (n > 0) {
        sum += n % 10;
        n /= 10;
    }
    return sum;
}

public int minimumBeautiful(int n, int target) {
    int x = 0;
    while (digitSum(n + x) > target) {
        ++x;
    }
    return x;
}
```

